 (gen_random_uuid(), 'product_cost_total', 1, 'metric', '商品成本总额', '按订单商品明细关联 product_costs，累计 SUM(product_costs.unit_cost)。不得使用商品售价、订单金额或库存金额代替成本。', ARRAY['order_items','product_costs'], ARRAY['order_items.product_id','product_costs.product_id','product_costs.unit_cost'], ARRAY['商品成本总额','总成本','商品总成本'], 'sum', '{"plan":{"measures":[{"name":"product_cost_total","operation":"sum"}],"expected_columns":["product_cost_total"],"expected_row_shape":"single"}}'::jsonb, 'data-team', 'enabled'),
 (gen_random_uuid(), 'refund_order_rate', 1, 'metric', '退款订单率', '退款订单数除以订单总数，使用 COUNT(DISTINCT refunds.order_id) / NULLIF(COUNT(DISTINCT orders.id), 0) * 100，并 ROUND 到两位小数。', ARRAY['orders','refunds'], ARRAY['orders.id','refunds.order_id'], ARRAY['退款订单率','退款率是多少'], 'ratio', '{"plan":{"measures":[{"name":"refund_order_rate","operation":"ratio"}],"expected_columns":["refund_order_rate"],"expected_row_shape":"single"}}'::jsonb, 'data-team', 'enabled'),
